class Solution {
public:
    bool check(vector<int>& nums) {
        // write your code here
        int n = nums.size();
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] > nums[(i + 1) % n]) {
                cnt++;
            }
        }
        return cnt <= 1;
    }
};

code.Python3:
class Solution(object):
    def check(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        n = len(nums)
        cnt = 0
        for i in range(n):
            if nums[i] > nums[(i + 1) % n]:
                cnt += 1
        return cnt <= 1

